+import type { ConfigOptions } from "./types.ts";
+import { ConfigParseError } from "./errors.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const paths = options.searchPaths?.length ? options.searchPaths : [cwd()];
+  const formats = options.formats?.length ? options.formats : [".json", ".rc"];
+  const values: Record<string, unknown> = {};
+  let firstPath: string | undefined;
+
+  for (const searchPath of paths) {
+    for (const format of formats) {
+      const path = await resolvePath(searchPath, `${options.name}${format}`);
+      const content = await readTextIfFile(path);
+      if (content === undefined) continue;
+
+      const parsed = parseConfig(content, path, format, options.parser);
+      firstPath ??= path;
+      if (!options.mergeConfigs) return { path, values: flatten(parsed) };
+      for (const [key, value] of Object.entries(flatten(parsed))) {
+        if (!(key in values)) values[key] = value;
+      }
+      break;
+    }
+  }
+  return { path: firstPath, values };
+}
+
+function parseConfig(content: string, path: string, format: string, parser?: ConfigOptions["parser"]): Record<string, unknown> {
+  try {
+    const value = parser ? parser(content) : format === ".json" ? JSON.parse(content) : parseRc(content);
+    if (!isPlainObject(value)) throw new Error("Config root must be a plain object.");
+    return value;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const equals = trimmed.indexOf("=");
+    if (equals < 1) throw new Error(`Invalid RC line: ${line}`);
+    const key = trimmed.slice(0, equals).trim();
+    let value = trimmed.slice(equals + 1).trim();
+    if (value.startsWith('"') && value.endsWith('"') && value.length >= 2) value = value.slice(1, -1);
+    values[key] = value;
+  }
+  return values;
+}
+
+function flatten(value: Record<string, unknown>, prefix = ""): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [rawKey, child] of Object.entries(value)) {
+    const key = toCamelCase(rawKey);
+    const path = prefix ? `${prefix}.${key}` : key;
+    if (isPlainObject(child)) Object.assign(result, flatten(child, path));
+    else result[path] = child;
+  }
+  return result;
+}
+
+function toCamelCase(value: string): string {
+  return value.replace(/-([a-zA-Z0-9])/g, (_, char: string) => char.toUpperCase());
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  return !!value && typeof value === "object" && !Array.isArray(value) && Object.getPrototypeOf(value) === Object.prototype;
+}
+
+function cwd(): string {
+  // deno-lint-ignore no-explicit-any
+  const runtime = globalThis as any;
+  return runtime.Deno?.cwd() ?? runtime.process?.cwd();
+}
+
+async function resolvePath(directory: string, file: string): Promise<string> {
+  // deno-lint-ignore no-explicit-any
+  const runtime = globalThis as any;
+  if (runtime.Deno) return runtime.Deno.realPath?.(directory).then((path: string) => `${path}/${file}`).catch(() => `${directory}/${file}`) ?? `${directory}/${file}`;
+  const path = await import("node:path");
+  return path.resolve(directory, file);
+}
+
+async function readTextIfFile(path: string): Promise<string | undefined> {
+  try {
+    // deno-lint-ignore no-explicit-any
+    const runtime = globalThis as any;
+    if (runtime.Deno) return await runtime.Deno.readTextFile(path);
+    const fs = await import("node:fs/promises");
+    return await fs.readFile(path, "utf8");
+  } catch (error) {
+    if (error instanceof Error && ("name" in error) && (error.name === "NotFound" || (error as { code?: string }).code === "ENOENT")) return undefined;
+    throw error;
+  }
+}
