+import { test } from "@cliffy/internal/testing/test";
+import { assertEquals, assertRejects } from "@std/assert";
+import {
+  Command,
+  ConfigParseError,
+  ConfigValidationError,
+} from "../../mod.ts";
+
+async function withConfigs(
+  files: Record<string, string>,
+  action: (directory: string) => Promise<void>,
+) {
+  const directory = await Deno.makeTempDir();
+  try {
+    for (const [name, content] of Object.entries(files)) {
+      await Deno.writeTextFile(`${directory}/${name}`, content);
+    }
+    await action(directory);
+  } finally {
+    await Deno.remove(directory, { recursive: true });
+  }
+}
+
+test("command: config loads JSON defaults with CLI precedence", async () => {
+  await withConfigs({
+    "app.json": JSON.stringify({ port: 3000, enabled: false, tags: ["a", "b"], nested: { "some-key": 0 } }),
+  }, async (directory) => {
+    const command = new Command()
+      .throwErrors()
+      .config({ name: "app", searchPaths: [directory] })
+      .option("--port <port:number>", "")
+      .option("--enabled", "")
+      .option("--tags <tag:string>", "", { collect: true })
+      .option("--nested.some-key <value:number>", "");
+    const result = await command.parse(["--port", "4000"]);
+
+    assertEquals(result.options, {
+      port: 4000,
+      enabled: false,
+      tags: ["a", "b"],
+      nested: { someKey: 0 },
+    });
+    assertEquals(command.getConfigValues(), {
+      port: 3000,
+      enabled: false,
+      tags: ["a", "b"],
+      "nested.someKey": 0,
+    });
+    assertEquals(command.getConfigPath(), `${directory}/app.json`);
+  });
+});
+
+test("command: config loads RC files and ignores unknown values", async () => {
+  await withConfigs({
+    "app.rc": '# comment\
port=3000\
title="hello world"\
unknown=true\
',
+  }, async (directory) => {
+    const result = await new Command()
+      .throwErrors()
+      .config({ name: "app", searchPaths: [directory] })
+      .option("--port <port:number>", "")
+      .option("--title <title:string>", "")
+      .parse([]);
+    assertEquals(result.options, { port: 3000, title: "hello world" });
+  });
+});
+
+test("command: config reports malformed and invalid values", async () => {
+  await withConfigs({ "app.json": "{" }, async (directory) => {
+    await assertRejects(
+      () => new Command().throwErrors().config({ name: "app", searchPaths: [directory] }).parse([]),
+      ConfigParseError,
+    );
+  });
+  await withConfigs({ "app.json": '{"port":"nope"}' }, async (directory) => {
+    await assertRejects(
+      () => new Command().throwErrors().config({ name: "app", searchPaths: [directory] }).option("--port <port:number>", "").parse([]),
+      ConfigValidationError,
+    );
+  });
+});
+
+test("command: subcommands inherit and override config values", async () => {
+  await withConfigs({ "parent.json": '{"port":1}' }, async (directory) => {
+    const child = new Command()
+      .config({ name: "child", searchPaths: [directory], parser: () => ({ port: 2 }) })
